package com.example.biometricauth;

import android.content.Context;
import android.content.SharedPreferences;
import android.util.Log;

/**
 * Manages user session state. In a real app, this would communicate with
 * a backend server to validate tokens, refresh sessions, etc.
 */
public class SessionManager {

    private static final String TAG = "SessionManager";
    private static final String PREFS_NAME = "session_prefs";
    private static final String KEY_SESSION_TOKEN = "session_token";
    private static final String KEY_USERNAME = "username";

    private final SharedPreferences prefs;

    public SessionManager(Context context) {
        this.prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }

    /**
     * Simulate a password-based login. In production, this would call your backend API.
     * Returns a session token on success, null on failure.
     */
    public String loginWithPassword(String username, String password) {
        // TODO: Replace with actual server-side authentication
        // This is a placeholder that simulates a successful login
        if (username != null && !username.isEmpty() && password != null && !password.isEmpty()) {
            // In production: POST to /api/auth/login, receive a JWT or session token
            String sessionToken = "server_session_" + System.currentTimeMillis() + "_" + username.hashCode();
            saveSession(username, sessionToken);
            Log.d(TAG, "Password login successful for user: " + username);
            return sessionToken;
        }
        return null;
    }

    /**
     * Validate a session token. In production, this MUST call the backend server.
     * 
     * This is the critical security gate — after biometric decryption returns a token,
     * this method must verify it's still valid server-side.
     */
    public boolean validateSessionToken(String sessionToken) {
        if (sessionToken == null || sessionToken.isEmpty()) {
            return false;
        }

        // TODO: Replace with actual server-side token validation
        // In production: POST to /api/auth/validate with the token
        // The server checks if the token is still valid, not expired, not revoked, etc.
        //
        // Example:
        // Response response = apiClient.validateToken(sessionToken);
        // return response.isValid();

        // Placeholder: check if token matches what we have stored
        // In production, ALWAYS validate server-side
        String storedToken = prefs.getString(KEY_SESSION_TOKEN, null);
        boolean isValid = sessionToken.equals(storedToken);

        Log.d(TAG, "Token validation result: " + isValid);
        return isValid;
    }

    /**
     * Get the current session token (for biometric enrollment).
     */
    public String getCurrentSessionToken() {
        return prefs.getString(KEY_SESSION_TOKEN, null);
    }

    /**
     * Get the current username.
     */
    public String getCurrentUsername() {
        return prefs.getString(KEY_USERNAME, null);
    }

    /**
     * Check if there's an active session.
     */
    public boolean hasActiveSession() {
        return prefs.getString(KEY_SESSION_TOKEN, null) != null;
    }

    /**
     * Save session data after successful authentication.
     */
    public void saveSession(String username, String sessionToken) {
        prefs.edit()
                .putString(KEY_USERNAME, username)
                .putString(KEY_SESSION_TOKEN, sessionToken)
                .apply();
    }

    /**
     * Clear session data on logout.
     */
    public void clearSession() {
        prefs.edit().clear().apply();
        Log.d(TAG, "Session cleared.");
    }
}


// LoginActivity.java
package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;
import android.util.Log;
import android.view.View;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricPrompt;

public class LoginActivity extends AppCompatActivity {

    private static final String TAG = "LoginActivity";

    private EditText editUsername;
    private EditText editPassword;
    private Button btnLogin;
    private Button btnBiometricLogin;
    private CheckBox checkEnableBiometric;
    private LinearLayout passwordLoginLayout;
    private TextView textStatus;
    private ProgressBar progressBar;

    private BiometricAuthManager biometricAuthManager;
    private SessionManager sessionManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        biometricAuthManager = new BiometricAuthManager(this);
        sessionManager = new SessionManager(this);

        initViews();
        setupListeners();
        checkBiometricLoginAvailability();
    }

    private void initViews() {
        editUsername = findViewById(R.id.edit_username);
        editPassword = findViewById(R.id.edit_password);
        btnLogin = findViewById(R.id.btn_login);
        btnBiometricLogin = findViewById(R.id.btn_biometric_login);
        checkEnableBiometric = findViewById(R.id.check_enable_biometric);
        passwordLoginLayout = findViewById(R.id.password_login_layout);
        textStatus = findViewById(R.id.text_status);
        progressBar = findViewById(R.id.progress_bar);
    }

    private void setupListeners() {
        btnLogin.setOnClickListener(v -> performPasswordLogin());
        btnBiometricLogin.setOnClickListener(v -> performBiometricLogin());
    }

    /**
     * Check if biometric login is available and enrolled, and show/hide UI accordingly.
     */
    private void checkBiometricLoginAvailability() {
        BiometricAuthManager.BiometricAvailability availability =
                biometricAuthManager.checkBiometricAvailability();

        switch (availability) {
            case AVAILABLE:
                if (biometricAuthManager.isBiometricLoginEnrolled()) {
                    // Show biometric login button prominently
                    btnBiometricLogin.setVisibility(View.VISIBLE);
                    checkEnableBiometric.setVisibility(View.GONE);
                    textStatus.setText("Tap the fingerprint button to log in, or use your password.");
                    textStatus.setVisibility(View.VISIBLE);

                    // Auto-trigger biometric prompt
                    performBiometricLogin();
                } else {
                    // Biometric available but not enrolled — show option to enable
                    btnBiometricLogin.setVisibility(View.GONE);
                    checkEnableBiometric.setVisibility(View.VISIBLE);
                    checkEnableBiometric.setText("Enable fingerprint login");
                }
                break;

            case NO_HARDWARE:
                btnBiometricLogin.setVisibility(View.GONE);
                checkEnableBiometric.setVisibility(View.GONE);
                break;

            case NOT_ENROLLED:
                btnBiometricLogin.setVisibility(View.GONE);
                checkEnableBiometric.setVisibility(View.GONE);
                textStatus.setText("No fingerprints enrolled on this device. Set up fingerprints in Settings to enable biometric login.");
                textStatus.setVisibility(View.VISIBLE);
                break;

            case HARDWARE_UNAVAILABLE:
            case SECURITY_UPDATE_REQUIRED:
            case UNKNOWN_ERROR:
                btnBiometricLogin.setVisibility(View.GONE);
                checkEnableBiometric.setVisibility(View.GONE);
                break;
        }
    }

    /**
     * Perform password-based login. If biometric enrollment is requested,
     * enroll after successful password auth.
     */
    private void performPasswordLogin() {
        String username = editUsername.getText().toString().trim();
        String password = editPassword.getText().toString().trim();

        if (username.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Please enter username and password.", Toast.LENGTH_SHORT).show();
            return;
        }

        setLoading(true);

        // Simulate async login (in production, use a background thread / coroutine)
        String sessionToken = sessionManager.loginWithPassword(username, password);

        if (sessionToken != null) {
            Log.d(TAG, "Password login successful.");

            if (checkEnableBiometric.isChecked() && biometricAuthManager.isBiometricAvailable()) {
                // Enroll biometric login with the session token
                enrollBiometricAfterLogin(sessionToken);
            } else {
                // Proceed directly to main screen
                setLoading(false);
                navigateToMain();
            }
        } else {
            setLoading(false);
            Toast.makeText(this, "Invalid username or password.", Toast.LENGTH_SHORT).show();
            textStatus.setText("Login failed. Please try again.");
            textStatus.setVisibility(View.VISIBLE);
        }
    }

    /**
     * Enroll biometric login after successful password authentication.
     * The session token is encrypted with a biometric-bound Keystore key.
     */
    private void enrollBiometricAfterLogin(String sessionToken) {
        biometricAuthManager.enrollBiometricLogin(this, sessionToken,
                new BiometricAuthManager.BiometricAuthCallback() {
                    @Override
                    public void onAuthenticationSuccess(String decryptedSessionToken) {
                        // Not used during enrollment
                    }

                    @Override
                    public void onEnrollmentSuccess() {
                        setLoading(false);
                        Toast.makeText(LoginActivity.this,
                                "Fingerprint login enabled! You can use your fingerprint next time.",
                                Toast.LENGTH_LONG).show();
                        navigateToMain();
                    }

                    @Override
                    public void onAuthenticationError(int errorCode, String errorMessage) {
                        setLoading(false);
                        Log.w(TAG, "Biometric enrollment failed: " + errorMessage);
                        Toast.makeText(LoginActivity.this,
                                "Fingerprint setup failed. You can enable it later in Settings.",
                                Toast.LENGTH_LONG).show();
                        // Still navigate to main since password auth succeeded
                        navigateToMain();
                    }

                    @Override
                    public void onAuthenticationFailed() {
                        // Fingerprint not recognized — prompt stays open for retry
                        Toast.makeText(LoginActivity.this,
                                "Fingerprint not recognized. Try again.",
                                Toast.LENGTH_SHORT).show();
                    }
                });
    }

    /**
     * Perform biometric login. On success, the encrypted session token is decrypted
     * and then validated server-side before granting access.
     */
    private void performBiometricLogin() {
        setLoading(true);
        textStatus.setText("Authenticating...");
        textStatus.setVisibility(View.VISIBLE);

        biometricAuthManager.authenticateWithBiometric(this,
                new BiometricAuthManager.BiometricAuthCallback() {
                    @Override
                    public void onAuthenticationSuccess(String decryptedSessionToken) {
                        // CRITICAL: Validate the decrypted token server-side
                        // Do NOT just trust the token because biometric succeeded
                        boolean isTokenValid = sessionManager.validateSessionToken(decryptedSessionToken);

                        if (isTokenValid) {
                            setLoading(false);
                            Log.d(TAG, "Biometric login successful. Token validated.");
                            Toast.makeText(LoginActivity.this,
                                    "Welcome back!", Toast.LENGTH_SHORT).show();
                            navigateToMain();
                        } else {
                            setLoading(false);
                            Log.w(TAG, "Biometric auth succeeded but token is invalid/expired.");
                            // Token expired or revoked — require password login
                            biometricAuthManager.clearBiometricEnrollment();
                            Toast.makeText(LoginActivity.this,
                                    "Your session has expired. Please log in with your password.",
                                    Toast.LENGTH_LONG).show();
                            showPasswordLoginOnly();
                        }
                    }

                    @Override
                    public void onEnrollmentSuccess() {
                        // Not used during authentication
                    }

                    @Override
                    public void onAuthenticationError(int errorCode, String errorMessage) {
                        setLoading(false);
                        Log.w(TAG, "Biometric auth error [" + errorCode + "]: " + errorMessage);

                        if (errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON) {
                            // User chose "Use Password"
                            showPasswordLoginOnly();
                            textStatus.setText("Please enter your password.");
                        } else if (errorCode == BiometricPrompt.ERROR_LOCKOUT
                                || errorCode == BiometricPrompt.ERROR_LOCKOUT_PERMANENT) {
                            // Too many failed attempts
                            showPasswordLoginOnly();
                            textStatus.setText("Too many failed attempts. Please use your password.");
                        } else if (errorCode == BiometricPrompt.ERROR_USER_CANCELED
                                || errorCode == BiometricPrompt.ERROR_CANCELED) {
                            textStatus.setText("Authentication cancelled. Tap the fingerprint button to try again.");
                        } else {
                            textStatus.setText(errorMessage);
                            // For key invalidation errors, show password login
                            showPasswordLoginOnly();
                        }
                        textStatus.setVisibility(View.VISIBLE);
                    }

                    @Override
                    public void onAuthenticationFailed() {
                        // Fingerprint not recognized — prompt stays open for retry
                        Toast.makeText(LoginActivity.this,
                                "Fingerprint not recognized. Try again.",
                                Toast.LENGTH_SHORT).show();
                    }
                });
    }

    /**
     * Show only the password login form (hide biometric button).
     */
    private void showPasswordLoginOnly() {
        passwordLoginLayout.setVisibility(View.VISIBLE);
        btnBiometricLogin.setVisibility(View.GONE);
        checkEnableBiometric.setVisibility(View.GONE);
    }

    private void setLoading(boolean loading) {
        progressBar.setVisibility(loading ? View.VISIBLE : View.GONE);
        btnLogin.setEnabled(!loading);
        btnBiometricLogin.setEnabled(!loading);
        editUsername.setEnabled(!loading);
        editPassword.setEnabled(!loading);
    }

    private void navigateToMain() {
        Intent intent = new Intent(this, MainActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }
}


// MainActivity.java
package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.Switch;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {

    private BiometricAuthManager biometricAuthManager;
    private SessionManager sessionManager;

    private TextView textWelcome;
    private Switch switchBiometric;
    private Button btnLogout;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        biometricAuthManager = new BiometricAuthManager(this);
        sessionManager = new SessionManager(this);

        // Verify we have a valid session
        if (!sessionManager.hasActiveSession()) {
            navigateToLogin();
            return;
        }

        initViews();
        setupListeners();
    }

    private void initViews() {
        textWelcome = findViewById(R.id.text_welcome);
        switchBiometric = findViewById(R.id.switch_biometric);
        btnLogout = findViewById(R.id.btn_logout);

        String username = sessionManager.getCurrentUsername();
        textWelcome.setText("Welcome, " + (username != null ? username : "User") + "!");

        // Set biometric switch state
        boolean biometricAvailable = biometricAuthManager.isBiometricAvailable();
        switchBiometric.setEnabled(biometricAvailable);
        switchBiometric.setChecked(biometricAuthManager.isBiometricLoginEnrolled());

        if (!biometricAvailable) {
            switchBiometric.setText("Fingerprint Login (Not Available)");
        }
    }

    private void setupListeners() {
        switchBiometric.setOnCheckedChangeListener((buttonView, isChecked) -> {
            if (isChecked) {
                enableBiometricLogin();
            } else {
                disableBiometricLogin();
            }
        });

        btnLogout.setOnClickListener(v -> performLogout());
    }

    private void enableBiometricLogin() {
        String sessionToken = sessionManager.getCurrentSessionToken();
        if (sessionToken == null) {
            Toast.makeText(this, "No active session. Please log in again.", Toast.LENGTH_SHORT).show();
            switchBiometric.setChecked(false);
            return;
        }

        biometricAuthManager.enrollBiometricLogin(this, sessionToken,
                new BiometricAuthManager.BiometricAuthCallback() {
                    @Override
                    public void onAuthenticationSuccess(String decryptedSessionToken) {
                        // Not used during enrollment
                    }

                    @Override
                    public void onEnrollmentSuccess() {
                        Toast.makeText(MainActivity.this,
                                "Fingerprint login enabled!", Toast.LENGTH_SHORT).show();
                    }

                    @Override
                    public void onAuthenticationError(int errorCode, String errorMessage) {
                        switchBiometric.setChecked(false);
                        Toast.makeText(MainActivity.this,
                                "Failed to enable fingerprint login: " + errorMessage,
                                Toast.LENGTH_LONG).show();
                    }

                    @Override
                    public void onAuthenticationFailed() {
                        Toast.makeText(MainActivity.this,
                                "Fingerprint not recognized.", Toast.LENGTH_SHORT).show();
                    }
                });
    }

    private void disableBiometricLogin() {
        new AlertDialog.Builder(this)
                .setTitle("Disable Fingerprint Login")
                .setMessage("Are you sure you want to disable fingerprint login?")
                .setPositiveButton("Disable", (dialog, which) -> {
                    biometricAuthManager.clearBiometricEnrollment();
                    Toast.makeText(this, "Fingerprint login disabled.", Toast.LENGTH_SHORT).show();
                })
                .setNegativeButton("Cancel", (dialog, which) -> {
                    switchBiometric.setChecked(true);
                })
                .setCancelable(false)
                .show();
    }

    private void performLogout() {
        new AlertDialog.Builder(this)
                .setTitle("Logout")
                .setMessage("Do you want to log out? This will also disable fingerprint login.")
                .setPositiveButton("Logout", (dialog, which) -> {
                    biometricAuthManager.clearBiometricEnrollment();
                    sessionManager.clearSession();
                    navigateToLogin();
                })
                .setNegativeButton("Cancel", null)
                .show();
    }

    private void navigateToLogin() {
        Intent intent = new Intent(this, LoginActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }
}